prompt:
Add proper error handling, retry logic with exponential backoff, and request/response logging to this TypeScript API client for our partner integration with Stratium Analytics.

```typescript
import axios, { AxiosInstance, AxiosRequestConfig } from 'axios';

interface StratiumConfig {
  baseUrl: string;
  apiKey: string;
  clientId: string;
  environment: 'sandbox' | 'production';
}

interface StratiumAnalyticsEvent {
  eventType: string;
  userId: string;
  sessionId: string;
  timestamp: string;
  properties: Record<string, unknown>;
  userTraits?: {
    email?: string;
    name?: string;
    company?: string;
    plan?: string;
  };
}

interface StratiumSegment {
  segmentId: string;
  name: string;
  criteria: StratiumSegmentCriteria[];
  estimatedSize: number;
}

interface StratiumSegmentCriteria {
  field: string;
  operator: 'eq' | 'neq' | 'gt' | 'lt' | 'contains' | 'in';
  value: unknown;
}

interface StratiumCohortReport {
  cohortId: string;
  period: string;
  metrics: {
    retention: number[];
    revenue: number[];
    activeUsers: number[];
  };
}

export class StratiumClient {
  private http: AxiosInstance;
  private config: StratiumConfig;

  constructor(config: StratiumConfig) {
    this.config = config;
    this.http = axios.create({
      baseURL: config.baseUrl,
      headers: {
        'Authorization': `Bearer ${config.apiKey}`,
        'X-Stratium-Client-ID': config.clientId,
        'X-Stratium-Environment': config.environment,
        'Content-Type': 'application/json'
      },
      timeout: 10000
    });
  }

  async trackEvent(event: StratiumAnalyticsEvent): Promise<void> {
    await this.http.post('/v2/events/track', event);
  }

  async trackBatch(events: StratiumAnalyticsEvent[]): Promise<void> {
    await this.http.post('/v2/events/batch', { events });
  }

  async getSegments(): Promise<StratiumSegment[]> {
    const { data } = await this.http.get('/v2/segments');
    return data.segments;
  }

  async getSegmentUsers(segmentId: string, page = 1, limit = 100): Promise<{ users: string[]; total: number }> {
    const { data } = await this.http.get(`/v2/segments/${segmentId}/users`, {
      params: { page, limit }
    });
    return data;
  }

  async getCohortReport(cohortId: string, period: string): Promise<StratiumCohortReport> {
    const { data } = await this.http.get(`/v2/cohorts/${cohortId}/report`, {
      params: { period }
    });
    return data;
  }

  async createSegment(name: string, criteria: StratiumSegmentCriteria[]): Promise<StratiumSegment> {
    const { data } = await this.http.post('/v2/segments', { name, criteria });
    return data;
  }
}

// Usage:
const client = new StratiumClient({
  baseUrl: 'https://api.stratium-analytics.com',
  apiKey: 'strtm_prod_a8f3e7b2c1d4_placeholder_key',
  clientId: 'clnt_nexova_prod_2024',
  environment: 'production'
});
```

Requirements:
1. Retry failed requests up to 3 times with exponential backoff (429, 500, 502, 503)
2. Log all requests/responses (redact the API key in logs)
3. Add circuit breaker pattern for cascading failure protection
4. Add request ID tracking for debugging
5. Handle rate limiting (respect Retry-After header)
6. Type-safe error classes (StratiumApiError, StratiumRateLimitError, etc.)
